mapper.select:
select u.id, u.username,u.real_name,u.student_id,u.user_type,u.email,u.status,u.grade,u.major, u.phone,u.avatar_url,u.last_login_time,u.last_login_ip,u.created_at,u.updated_at, u.violation_count, u.ban_until, IFNULL(res_stats.reservation_count, 0) AS reservation_count, IFNULL(res_stats.cancel_count, 0) AS cancel_count from users u LEFT JOIN ( SELECT user_id, COUNT(*) AS reservation_count, SUM(CASE WHEN status = 'cancelled' THEN 1 ELSE 0 END) AS cancel_count FROM reservations GROUP BY user_id ) res_stats ON u.id = res_stats.user_id
user_type NOT IN ('admin', 'super_admin')
and user_type = #{userType}
and status = #{status}
AND ( username LIKE CONCAT('%', #{usernameOrRealNameOrStudentId}, '%') OR real_name LIKE CONCAT('%', #{usernameOrRealNameOrStudentId}, '%') OR phone LIKE CONCAT('%', #{usernameOrRealNameOrStudentId}, '%') )
